from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal, InvalidOperation
from typing import Final


MoneyInput = Decimal | int | float | str


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when an item price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item does not exist in the cart."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


class ShoppingCart:
    """Manage cart items, discounts, and total calculations."""

    _MIN_PERCENTAGE: Final[Decimal] = Decimal("0")
    _MAX_PERCENTAGE: Final[Decimal] = Decimal("100")

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._percentage_discount: Decimal = Decimal("0")
        self._flat_discount: Decimal = Decimal("0")

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_price = self._validate_unit_price(unit_price)
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)

        if existing_item is None:
            self._items[normalized_product_name] = CartItem(
                product_name=normalized_product_name,
                unit_price=validated_price,
                quantity=validated_quantity,
            )
            return

        if existing_item.unit_price != validated_price:
            raise InvalidPriceError(
                f"Product '{normalized_product_name}' already exists with unit price "
                f"{existing_item.unit_price}; received {validated_price}."
            )

        self._items[normalized_product_name] = CartItem(
            product_name=normalized_product_name,
            unit_price=existing_item.unit_price,
            quantity=existing_item.quantity + validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_product_name)
        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_existing_item(normalized_product_name)

        self._items[normalized_product_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=validated_quantity,
        )

    def subtotal(self) -> Decimal:
        """Return the cart subtotal before discounts."""
        return sum(
            (cart_item.total_price for cart_item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount to the cart total."""
        validated_percentage = self._validate_percentage_discount(percentage)
        self._percentage_discount = validated_percentage
        self._flat_discount = Decimal("0")

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat discount to the cart total."""
        validated_amount = self._validate_flat_discount(amount)
        self._flat_discount = validated_amount
        self._percentage_discount = Decimal("0")

    def total(self) -> Decimal:
        """Return the final cart total after discounts."""
        current_subtotal = self.subtotal()
        discounted_total = current_subtotal - self._calculate_discount_amount(current_subtotal)
        return max(discounted_total, Decimal("0"))

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their details."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._percentage_discount = Decimal("0")
        self._flat_discount = Decimal("0")

    def _calculate_discount_amount(self, current_subtotal: Decimal) -> Decimal:
        if self._percentage_discount > Decimal("0"):
            return current_subtotal * (self._percentage_discount / Decimal("100"))

        return self._flat_discount

    def _get_existing_item(self, product_name: str) -> CartItem:
        try:
            return self._items[product_name]
        except KeyError as error:
            raise ItemNotFoundError(
                f"Product '{product_name}' does not exist in the cart."
            ) from error

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_product_name = product_name.strip()

        if not normalized_product_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_product_name

    @classmethod
    def _validate_unit_price(cls, unit_price: MoneyInput) -> Decimal:
        validated_price = cls._to_decimal(unit_price, "Unit price")

        if validated_price < Decimal("0"):
            raise InvalidPriceError("Unit price cannot be negative.")

        return validated_price

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

        return quantity

    @classmethod
    def _validate_percentage_discount(cls, percentage: MoneyInput) -> Decimal:
        validated_percentage = cls._to_decimal(percentage, "Percentage discount")

        if not cls._MIN_PERCENTAGE <= validated_percentage <= cls._MAX_PERCENTAGE:
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        return validated_percentage

    @classmethod
    def _validate_flat_discount(cls, amount: MoneyInput) -> Decimal:
        validated_amount = cls._to_decimal(amount, "Flat discount")

        if validated_amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount cannot be negative.")

        return validated_amount

    @staticmethod
    def _to_decimal(value: MoneyInput, field_name: str) -> Decimal:
        try:
            decimal_value = Decimal(str(value))
        except (InvalidOperation, ValueError) as error:
            raise InvalidDiscountError(f"{field_name} must be a valid number.") from error

        if not decimal_value.is_finite():
            raise InvalidDiscountError(f"{field_name} must be a finite number.")

        return decimal_value
